package main

import (
	"encoding/xml"
	"io"
	"os"
	"strings"
)

const header = `// This file has been generated by
// go-Vulkan please do not edit.

package vulkan

`

type Type struct {
	Category string `xml:"category,attr"`
	NameAttr string `xml:"name,attr"` // for attribute-style
	NameElem string `xml:"name"`      // for element-style
	InnerXML string `xml:",innerxml"` // full raw body
}

type VkParser struct {
	structures strings.Builder
	functions  strings.Builder
	enums      strings.Builder
}

func (p *VkParser) Process(file *os.File) error {
	decoder := xml.NewDecoder(file)

	p.structures.WriteString(header)
	p.functions.WriteString(header)
	p.enums.WriteString(header)

	for {
		tok, err := decoder.Token()
		if err == io.EOF {
			return nil
		}
		if err != nil {
			return err
		}

		se, ok := tok.(xml.StartElement)
		if !ok {
			continue
		}

		switch se.Name.Local {
		case "type":
			err := p.parseType(decoder, se)
			if err != nil {
				return err
			}

		case "enums":
			var enum Enumeration
			if err := decoder.DecodeElement(&enum, &se); err != nil {
				return err
			}

			err := p.parseEnum(enum)
			if err != nil {
				return err
			}
		default:
		}

	}
}

func (p *VkParser) parseType(decoder *xml.Decoder, se xml.StartElement) error {
	var t Type
	if err := decoder.DecodeElement(&t, &se); err != nil {
		return err
	}

	if t.Category == "" {
		return nil
	}

	var name string
	if t.NameAttr != "" {
		name = t.NameAttr
	} else {
		name = t.NameElem
	}

	switch t.Category {
	case "struct":
		err := p.parseStruct(name, []byte(t.InnerXML))
		if err != nil {
			return err
		}
	case "funcpointer":
		err := p.parseFuncPointer([]byte(t.InnerXML))
		if err != nil {
			return err
		}
	default:
		//fmt.Println("Unhandled type:", t.Category, name)
	}

	return nil
}

func (p *VkParser) Save() error {
	err := os.WriteFile("./pkg/raw/functions.go", []byte(p.functions.String()), 0644)
	if err != nil {
		return err
	}

	err = os.WriteFile("./pkg/raw/structures.go", []byte(p.structures.String()), 0644)
	if err != nil {
		return err
	}

	err = os.WriteFile("./pkg/raw/enums.go", []byte(p.enums.String()), 0644)
	if err != nil {
		return err
	}

	return nil
}
